import{_ as l,o as e,c as o,e as p,f as i}from"./app-86209b8c.js";const t={},c=i('<h2 id="框架入口" tabindex="-1"><a class="header-anchor" href="#框架入口" aria-hidden="true">#</a> 框架入口</h2><blockquote><p>框架的功能模块都放在 mk 内</p></blockquote><figure><img src="https://gitee.com/muzzik/images/raw/master/mk-framework/quick-start/2/Q4TSKKFA]Y_2)MT70T$UCX7.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="主要模块介绍" tabindex="-1"><a class="header-anchor" href="#主要模块介绍" aria-hidden="true">#</a> 主要模块介绍</h2><ul><li><p>音频管理器 - mk.audio</p><blockquote><p>音频播放，状态，以及事件管理</p></blockquote></li><li><p>新手引导</p><ul><li><p>引导管理器 - mk.guide_manage:</p><blockquote><p>新手引导步骤切换/还原，事件管理</p></blockquote></li><li><p>引导步骤基类 - mk.guide_step_base</p><blockquote><p>可挂载式的步骤脚本，包含引导步骤生命周期，由引导管理器控制</p></blockquote></li></ul></li><li><p>多语言</p><ul><li><p>多语言管理器 - mk.language_manage</p><blockquote><p>控制当前语言的切换，用于语言的(文本/图片)数据(注册/获取)，语言的事件管理</p></blockquote></li><li><p>多语言文本 - mk.language.label</p><blockquote><p>挂载式组件，控制多语言文本的展示</p></blockquote></li><li><p>多语言图片 - mk.language.texture</p><blockquote><p>挂载式组件，控制多语言图片的展示</p></blockquote></li><li><p>多语言节点 - mk.language.node</p><blockquote><p>挂载式组件，控制多语言不同状态的节点展示</p></blockquote></li></ul></li><li><p>模块系统</p><ul><li><p>视图组件基类 - mk.view_base</p><blockquote><p>所有 ui 模块的父类组件，代替 cc.Component</p></blockquote></li><li><p>生命周期组件 - mk.life_cycle</p><blockquote><p>mk.view_base 的父类，控制组件生命周期以及自身资源的管理</p></blockquote></li><li><p>层级组件 - mk.layer</p><blockquote><p>mk.life_cycle 的父类，用于渲染次序控制，渲染层级分类，支持细粒度和自定义层级分类</p></blockquote></li></ul></li><li><p>网络系统</p><ul><li><p>http 服务 - mk.http</p></li><li><p>websocket - mk.network.websocket</p></li><li><p>websocket(微信) - mk.network.websocket_wx</p></li></ul></li><li><p>资源系统</p><ul><li><p>资源管理器 - mk.asset</p><blockquote><p>资源的加载与自动释放管理</p></blockquote></li><li><p>bundle 管理器 - mk.bundle</p><blockquote><p>负责 bundle 加载/重载(热更)，scene 加载/预加载，事件管理</p></blockquote></li></ul></li><li><p>数据管理</p><ul><li><p>数据共享器 - mk.data_sharer</p><blockquote><p>用于模块间共享数据</p></blockquote></li><li><p>存储器 - mk.storage</p><blockquote><p>本地数据读写</p></blockquote></li><li><p>监听器 - mk.monitor</p><blockquote><p>数据观察者，监听数据修改，可用于 mvvm，数据跟踪调试</p></blockquote></li></ul></li></ul>',5);function u(k,a){return e(),o("div",null,[p(" more "),c])}const m=l(t,[["render",u],["__file","2.html.vue"]]);export{m as default};
